"use client";

import { useState, useRef, useMemo } from "react";
import { Canvas, useFrame, useThree } from "@react-three/fiber";
import { OrbitControls, Html, Float, Edges, Trail } from "@react-three/drei";
import * as THREE from "three";

type FlowState = "IDLE" | "WRITE" | "READ" | "FAILOVER";

// Data Packets (Particles) system
function FlowParticles({ source, target, color, active }: { source: THREE.Vector3, target: THREE.Vector3, color: string, active: boolean }) {
  const meshRef = useRef<THREE.Mesh>(null);
  const [progress, setProgress] = useState(0);

  useFrame((_, delta) => {
    if (!active) {
      if (meshRef.current) meshRef.current.visible = false;
      return;
    }
    if (meshRef.current) {
      meshRef.current.visible = true;
      setProgress((p) => (p >= 1 ? 0 : p + delta * 1.5));
      meshRef.current.position.lerpVectors(source, target, progress);
    }
  });

  return (
    <Trail width={1.5} length={4} color={new THREE.Color(color)} attenuation={(t) => t * t}>
      <mesh ref={meshRef}>
        <sphereGeometry args={[0.08]} />
        <meshBasicMaterial color={color} />
      </mesh>
    </Trail>
  );
}

const NodeLabel = ({ text, subtext }: { text: string, subtext: string }) => (
  <Html position={[0, -1.8, 0]} center zIndexRange={[100, 0]}>
    <div className="bg-black/90 border border-white/20 px-3 py-2 text-center shadow-[0_0_15px_rgba(0,0,0,0.8)] backdrop-blur-md min-w-[120px] select-none pointer-events-none group">
      <p className="text-white text-[9px] font-bold tracking-widest uppercase font-mono">{text}</p>
      <p className="text-white/40 text-[7px] tracking-widest mt-1 uppercase font-mono">{subtext}</p>
    </div>
  </Html>
);

function ArchitectureScene({ flowState }: { flowState: FlowState }) {
  // Node Positions
  const posUser = new THREE.Vector3(0, 3, 0);
  const posLB = new THREE.Vector3(0, 1.5, 0);
  const posApp1 = new THREE.Vector3(-1.5, 0, 0);
  const posApp2 = new THREE.Vector3(1.5, 0, 0);
  const posRedis = new THREE.Vector3(3, -1.5, 0);
  
  const posDbMaster = new THREE.Vector3(-2, -3, 0);
  const posDbRep1 = new THREE.Vector3(0, -3, -1);
  const posDbRep2 = new THREE.Vector3(2, -3, -1);
  
  const posS3 = new THREE.Vector3(-4, -4, -2);
  
  const { clock } = useThree();
  const dbMasterRef = useRef<THREE.Group>(null);
  const dbRep1Ref = useRef<THREE.Group>(null);

  useFrame(() => {
    // Failover Simulation logic: Master shakes/drops, Replica 1 glows and moves up slightly
    if (flowState === "FAILOVER") {
      if (dbMasterRef.current) {
        dbMasterRef.current.position.y -= 0.05;
        dbMasterRef.current.rotation.x += 0.05;
        dbMasterRef.current.children[0].material.color.lerp(new THREE.Color("#333333"), 0.1);
        dbMasterRef.current.children[0].material.emissiveIntensity = 0;
      }
      if (dbRep1Ref.current) {
        dbRep1Ref.current.position.lerp(new THREE.Vector3(-2, -3, 0), 0.05); // Takes master spot
        dbRep1Ref.current.children[0].material.emissive.lerp(new THREE.Color("#ff3333"), 0.1);
      }
    } else {
      // Reset logic (abbreviated for smoothness)
      if (dbMasterRef.current) {
        dbMasterRef.current.position.lerp(posDbMaster, 0.1);
        dbMasterRef.current.rotation.x = THREE.MathUtils.lerp(dbMasterRef.current.rotation.x, 0, 0.1);
        const targetColor = flowState === "WRITE" ? "#ff4400" : "#222222";
        dbMasterRef.current.children[0].material.color.lerp(new THREE.Color(targetColor), 0.1);
        dbMasterRef.current.children[0].material.emissive.lerp(new THREE.Color(targetColor), 0.1);
        dbMasterRef.current.children[0].material.emissiveIntensity = flowState === "WRITE" ? 2 : 0.2;
      }
      if (dbRep1Ref.current) {
         dbRep1Ref.current.position.lerp(posDbRep1, 0.1);
         const targetColor = flowState === "READ" ? "#00ffff" : "#222222";
         dbRep1Ref.current.children[0].material.emissive.lerp(new THREE.Color(targetColor), 0.1);
      }
    }
  });

  return (
    <group position={[0, 0.5, 0]}>
      {/* User */}
      <Float speed={2} floatIntensity={0.5}>
        <group position={posUser}>
          <mesh>
            <sphereGeometry args={[0.3, 16, 16]} />
            <meshStandardMaterial color="#ffffff" emissive="#ffffff" emissiveIntensity={0.5} />
            <NodeLabel text="Client" subtext="Requests" />
          </mesh>
        </group>
      </Float>

      {/* Load Balancer */}
      <group position={posLB}>
        <mesh>
          <boxGeometry args={[1.5, 0.4, 0.5]} />
          <meshStandardMaterial color="#111" metalness={0.8} />
          <Edges color="#fff" opacity={0.5} transparent />
          <NodeLabel text="HAProxy LB" subtext="Traffic Routing" />
        </mesh>
      </group>

      {/* Application Servers */}
      <group position={posApp1}>
        <mesh>
           <boxGeometry args={[0.8, 1.2, 0.8]} />
           <meshStandardMaterial color="#111" />
           <Edges color={flowState === "IDLE" ? "#444" : "#fff"} />
           <NodeLabel text="App Node 01" subtext="Next.js / Node" />
        </mesh>
      </group>
      <group position={posApp2}>
        <mesh>
           <boxGeometry args={[0.8, 1.2, 0.8]} />
           <meshStandardMaterial color="#111" />
           <Edges color={flowState === "IDLE" ? "#444" : "#fff"} />
           <NodeLabel text="App Node 02" subtext="Next.js / Node" />
        </mesh>
      </group>

      {/* Redis Cache */}
      <group position={posRedis}>
        <mesh>
          <boxGeometry args={[1, 1, 1]} />
          <meshStandardMaterial color="#1a0033" emissive="#bb00ff" emissiveIntensity={flowState === "READ" ? 1 : 0.2} />
          <Edges color="#bb00ff" />
          <NodeLabel text="Redis Cache" subtext="In-Memory" />
        </mesh>
      </group>

      {/* Primary DB */}
      <group ref={dbMasterRef} position={posDbMaster}>
        <mesh>
          <cylinderGeometry args={[0.6, 0.6, 1.5, 32]} />
          <meshStandardMaterial color="#222" metalness={0.9} roughness={0.1} emissive="#ff4400" emissiveIntensity={0.2} />
          <Edges color="#ff4400" />
          <NodeLabel text="Primary DB" subtext="MySQL Write Node" />
        </mesh>
      </group>

      {/* Read Replicas */}
      <group ref={dbRep1Ref} position={posDbRep1}>
        <mesh>
          <cylinderGeometry args={[0.5, 0.5, 1.2, 32]} />
          <meshStandardMaterial color="#222" emissive="#00ffff" emissiveIntensity={flowState === "READ" ? 1 : 0.1} />
          <Edges color="#00ffff" />
          <NodeLabel text="Replica 01" subtext="Async Read" />
        </mesh>
      </group>
      <group position={posDbRep2}>
        <mesh>
          <cylinderGeometry args={[0.5, 0.5, 1.2, 32]} />
          <meshStandardMaterial color="#222" emissive="#00ffff" emissiveIntensity={flowState === "READ" ? 1 : 0.1} />
          <Edges color="#00ffff" />
          <NodeLabel text="Replica 02" subtext="Async Read" />
        </mesh>
      </group>

      {/* S3 Backup */}
      <group position={posS3}>
        <mesh>
          <boxGeometry args={[2, 0.2, 2]} />
          <meshStandardMaterial color="#050505" />
          <Edges color="#ffffff" opacity={0.2} transparent />
          <NodeLabel text="Cloud Storage" subtext="S3 Cold Backup" />
        </mesh>
      </group>

      {/* Lines / Connections */}
      <line>
         <bufferGeometry attach="geometry" {...new THREE.BufferGeometry().setFromPoints([posUser, posLB])} />
         <lineBasicMaterial attach="material" color="#ffffff" opacity={0.2} transparent />
      </line>
      <line>
         <bufferGeometry attach="geometry" {...new THREE.BufferGeometry().setFromPoints([posLB, posApp1])} />
         <lineBasicMaterial attach="material" color="#ffffff" opacity={0.2} transparent />
      </line>
      <line>
         <bufferGeometry attach="geometry" {...new THREE.BufferGeometry().setFromPoints([posLB, posApp2])} />
         <lineBasicMaterial attach="material" color="#ffffff" opacity={0.2} transparent />
      </line>
      
      {/* Flow Particles */}
      {[posApp1, posApp2].map((app, i) => (
         <group key={i}>
            <FlowParticles source={posUser} target={posLB} color="#ffffff" active={flowState !== "IDLE"} />
            <FlowParticles source={posLB} target={app} color="#ffffff" active={flowState !== "IDLE"} />
            <FlowParticles source={app} target={posDbMaster} color="#ff4400" active={flowState === "WRITE"} />
            <FlowParticles source={app} target={posDbRep1} color="#00ffff" active={flowState === "READ"} />
            <FlowParticles source={app} target={posDbRep2} color="#00ffff" active={flowState === "READ"} />
            <FlowParticles source={app} target={posRedis} color="#bb00ff" active={flowState === "READ"} />
         </group>
      ))}
      <FlowParticles source={posDbMaster} target={posS3} color="#44aa44" active={flowState === "WRITE" || flowState === "IDLE"} />
      <FlowParticles source={posDbMaster} target={posDbRep1} color="#ffffff" active={flowState === "WRITE"} />
      <FlowParticles source={posDbMaster} target={posDbRep2} color="#ffffff" active={flowState === "WRITE"} />
    </group>
  );
}

export default function SystemDiagram() {
  const [flowState, setFlowState] = useState<FlowState>("IDLE");

  return (
    <section id="architecture" className="py-24 px-4 max-w-7xl mx-auto border-t border-white/10 font-mono relative z-10 w-full overflow-hidden">
      <div className="mb-12 flex flex-col md:flex-row justify-between items-end">
        <h2 className="text-4xl md:text-5xl font-bold text-white tracking-tighter uppercase mix-blend-difference">
          Active <br/> 
          <span className="text-transparent bg-clip-text bg-gradient-to-r from-neon-cyan to-white/30 tracking-widest italic">
            [Topology_Render]
          </span>
        </h2>
        
        {/* Interactive Controls */}
        <div className="flex flex-wrap gap-4 mt-8 md:mt-0 z-20 relative">
          <button 
            onClick={() => setFlowState("WRITE")}
            className={`px-4 py-2 border text-xs tracking-widest uppercase transition-all ${flowState === "WRITE" ? "bg-[#ff4400]/20 border-[#ff4400] text-[#ff4400] shadow-[0_0_15px_rgba(255,68,0,0.5)]" : "border-white/20 text-white/50 hover:border-white/50"}`}
          >
            &gt;_ Write Flow
          </button>
          <button 
            onClick={() => setFlowState("READ")}
            className={`px-4 py-2 border text-xs tracking-widest uppercase transition-all ${flowState === "READ" ? "bg-[#00ffff]/20 border-[#00ffff] text-[#00ffff] shadow-[0_0_15px_rgba(0,255,255,0.5)]" : "border-white/20 text-white/50 hover:border-white/50"}`}
          >
            &gt;_ Read Flow
          </button>
          <button 
            onClick={() => setFlowState("FAILOVER")}
            className={`px-4 py-2 border text-xs tracking-widest uppercase transition-all ${flowState === "FAILOVER" ? "bg-[#ff0000]/20 border-[#ff0000] text-[#ff0000] shadow-[0_0_15px_rgba(255,0,0,0.5)] animate-pulse" : "border-white/20 text-white/50 hover:border-white/50"}`}
          >
            [X] Failover
          </button>
          <button 
            onClick={() => setFlowState("IDLE")}
            className="px-4 py-2 border border-white/20 text-white/50 text-xs tracking-widest uppercase hover:text-white"
          >
            Reset
          </button>
        </div>
      </div>

      <div className="w-full h-[600px] bg-black border border-white/20 relative rounded-none shadow-[0_0_30px_rgba(255,255,255,0.02)]">
        {/* Subtle grid background */}
        <div className="absolute inset-0 opacity-[0.03] bg-[linear-gradient(to_right,#ffffff_1px,transparent_1px),linear-gradient(to_bottom,#ffffff_1px,transparent_1px)] bg-[size:3vw_3vw] pointer-events-none" />
        
        <Canvas camera={{ position: [0, 2, 10], fov: 50 }} dpr={[1, 2]}>
          <ambientLight intensity={0.2} />
          <directionalLight position={[0, 10, 5]} intensity={0.5} />
          <ArchitectureScene flowState={flowState} />
          <OrbitControls enableZoom={false} maxPolarAngle={Math.PI / 1.5} minPolarAngle={Math.PI / 4} enablePan={false} />
        </Canvas>

        {/* Legend */}
        <div className="absolute bottom-4 left-4 flex flex-col gap-2 pointer-events-none">
          <div className="flex items-center gap-2 text-[8px] uppercase tracking-widest text-white/50">
             <span className="w-2 h-2 rounded-full bg-[#ff4400] shadow-[0_0_5px_#ff4400]" /> Primary Write
          </div>
          <div className="flex items-center gap-2 text-[8px] uppercase tracking-widest text-white/50">
             <span className="w-2 h-2 rounded-full bg-[#00ffff] shadow-[0_0_5px_#00ffff]" /> Async Read
          </div>
          <div className="flex items-center gap-2 text-[8px] uppercase tracking-widest text-white/50">
             <span className="w-2 h-2 rounded-full bg-[#bb00ff] shadow-[0_0_5px_#bb00ff]" /> In-Memory Cache
          </div>
        </div>
      </div>
    </section>
  );
}
